     2| * HTTP client for orbi.kr API requests.
     3| *
     4| * Features:
     5| * - Token-bucket rate limiting to avoid overwhelming the server
     6| * - Exponential-backoff retry on transient errors (5xx / network)
     7| * - Configurable timeouts via AbortController
     8| * - Consistent User-Agent header
     9| *
    10| * @module utils/fetcher
    11| */
    12|// ---------------------------------------------------------------------------
    13|// Default configuration
    14|// ---------------------------------------------------------------------------
    15|const DEFAULT_CONFIG = {
    16|    baseUrl: "https://orbi.kr",
    17|    maxRetries: 3,
    18|    retryDelayMs: 1000,
    19|    rateLimitMs: 200,
    20|    timeoutMs: 15_000,
    21|};
    22|const USER_AGENT = "orbi-mcp/1.0.0 (MCP Server; +https://github.com/Move-AX/Orbi-Homepage-MCP)";
    23|// ---------------------------------------------------------------------------
    24|// Rate limiter (simple token-bucket approach)
    25|// ---------------------------------------------------------------------------
    26|let lastRequestTime = 0;
    27|/**
    28| * Wait until the rate-limit window has passed since the previous request.
    29| * This is intentionally process-global so that all tool handlers share a
    30| * single throttle.
    31| */
    32|async function waitForRateLimit(rateLimitMs) {
    33|    const now = Date.now();
    34|    const elapsed = now - lastRequestTime;
    35|    if (elapsed < rateLimitMs) {
    36|        await new Promise((resolve) => setTimeout(resolve, rateLimitMs - elapsed));
    37|    }
    38|    lastRequestTime = Date.now();
    39|}
    40|// ---------------------------------------------------------------------------
    41|// Core fetch wrapper
    42|// ---------------------------------------------------------------------------
    43|/** Errors thrown by the fetcher include the HTTP status when available. */
    44|export class FetchError extends Error {
    45|    status;
    46|    url;
    47|    constructor(message, status, url) {
    48|        super(message);
    49|        this.status = status;
    50|        this.url = url;
    51|        this.name = "FetchError";
    52|    }
