    61|/**
    62| * Perform a single HTTP GET request with timeout support.
    63| *
    64| * @param url      - Fully-qualified URL to fetch.
    65| * @param headers  - Additional headers to include.
    66| * @param timeoutMs - Timeout in milliseconds.
    67| * @returns The fetch Response object.
    68| */
    69|async function singleFetch(url, headers, timeoutMs) {
    70|    const controller = new AbortController();
    71|    const timer = setTimeout(() => controller.abort(), timeoutMs);
    72|    try {
    73|        const response = await fetch(url, {
    74|            method: "GET",
    75|            headers: {
    76|                "User-Agent": USER_AGENT,
    77|                Accept: "application/json",
    78|                ...headers,
    79|            },
    80|            signal: controller.signal,
    81|        });
    82|        return response;
    83|    }
    84|    finally {
    85|        clearTimeout(timer);
    86|    }
