    88|/**
    89| * Fetch JSON data from an orbi.kr API endpoint.
    90| *
    91| * The URL can be either:
    92| *  - An absolute URL (starts with "http")
    93| *  - A path relative to the configured base URL (e.g. "/api/v1/board/exam_list")
    94| *
    95| * @typeParam T - Expected shape of the parsed JSON response.
    96| * @param urlOrPath - Absolute URL or path segment.
    97| * @param options   - Optional headers and config overrides.
    98| * @returns Parsed JSON response.
    99| * @throws {FetchError} On non-retryable HTTP errors or after all retries are exhausted.
   100| */
   101|export async function fetchJson(urlOrPath, options = {}) {
   102|    const config = { ...DEFAULT_CONFIG, ...options.config };
   103|    const url = urlOrPath.startsWith("http")
   104|        ? urlOrPath
   105|        : `${config.baseUrl}${urlOrPath}`;
   106|    const headers = options.headers ?? {};
   107|    let lastError;
   108|    for (let attempt = 0; attempt <= config.maxRetries; attempt++) {
   109|        await waitForRateLimit(config.rateLimitMs);
