   121|            lastError = new FetchError(`HTTP ${response.status} (attempt ${attempt + 1}/${config.maxRetries + 1})`, response.status, url);
   122|        }
   123|        catch (err) {
   124|            if (err instanceof FetchError && err.status !== undefined && !isTransient(err.status)) {
